在 D:/llapk/app/src/main/java/com/multilanglearner/data/network/VideoDownloadService.kt 文件中：

添加使用 NewPipeExtractor 作为 YouTube 解析的首选方案。

1. 添加一个新的私有方法 fetchYoutubeNewPipe：
```kotlin
/**
 * 使用 NewPipeExtractor 解析 YouTube 视频
 * 这是专门为 Android 设计的库，不依赖 YouTube API
 */
private suspend fun fetchYoutubeNewPipe(url: String): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
    try {
        val videoId = extractYoutubeVideoId(url)
            ?: return@withContext Result.failure(Exception("无法提取 YouTube 视频 ID"))

        Log.d(TAG, "Using NewPipeExtractor for YouTube: $videoId")

        val streamInfo = org.schabi.newpipe.extractor.stream.StreamInfo.getInfo(
            org.schabi.newpipe.extractor.NewPipe.getService(0), 
            url
        )

        // 获取最佳视频流
        val videoStream = streamInfo.videoStreams
            .filter { it.isVideo }
            .maxByOrNull { it.height ?: 0 }

        // 获取音频流
        val audioStream = streamInfo.audioStreams
            .filter { it.isAudio }
            .maxByOrNull { it.averageBitrate ?: 0 }

        if (videoStream != null) {
            Result.success(VideoDownloadInfo(
                title = streamInfo.name ?: "YouTube 视频",
                downloadUrl = videoStream.url ?: "",
                cover = streamInfo.thumbnails?.firstOrNull()?.url,
                duration = streamInfo.duration?.toLong() ?: 0L,
                author = streamInfo.uploaderName,
                platform = VideoPlatform.YOUTUBE,
                audioUrl = audioStream?.url
            ))
        } else {
            Result.failure(Exception("无法获取视频流"))
        }
    } catch (e: Exception) {
        Log.e(TAG, "NewPipeExtractor error", e)
        Result.failure(e)
    }
}
```

2. 修改 fetchYoutubeInfo 方法，将 NewPipeExtractor 作为首选方案（在 InnerTube 之前尝试）：
```kotlin
private suspend fun fetchYoutubeInfo(url: String): Result<VideoDownloadInfo> {
    Log.d(TAG, "Fetching YouTube info for: $url")

    // 策略1: 尝试 NewPipeExtractor（推荐）
    val newPipeResult = fetchYoutubeNewPipe(url)
    if (newPipeResult.isSuccess) {
        Log.d(TAG, "NewPipeExtractor success")
        return newPipeResult
    }
    Log.w(TAG, "NewPipeExtractor failed: ${newPipeResult.exceptionOrNull()?.message}")

    // 策略2: 尝试 InnerTube API（备用）
    val innertubeResult = fetchYouTubeInnerTubeAPI(url)
    if (innertubeResult.isSuccess) {
        Log.d(TAG, "InnerTube API success")
        return innertubeResult
    }
    Log.w(TAG, "InnerTube API failed: ${innertubeResult.exceptionOrNull()?.message}")

    // 策略3: 尝试第三方API（最后备用）
    return fetchYouTubeThirdPartyAPI(url)
}
```

